apiVersion: "k8s.cni.cncf.io/v1"
kind: NetworkAttachmentDefinition
metadata:
  name: net-trust
spec:
  config: '{
    "cniVersion":"0.4.0",
    "name": "net-trust",
    "plugins": [
      {
        "type": "jcnr",               # --> CNI plugin is jcnr
        "args": {
          "vrfName": "trust",         # --> VRF name is trust
          "vrfTarget": "10:10"
        },
        "kubeConfig":"/etc/kubernetes/kubelet.conf"
      }
    ]  
  }'
---
apiVersion: v1
kind: Pod
metadata:
  name: pktgen-ce1
  labels:
     app: pktgen-odu
  annotations:
    k8s.v1.cni.cncf.io/networks: |
      [
        {
          "name": "net-trust",
          "interface":"net1",
          "cni-args": {
            "interfaceType":"veth",  
            "mac":"aa:bb:cc:dd:50:11",
            "ipConfig":{
              "ipv4":{
                "address":"10.111.1.10/24",      # --> IP address of the pod
                "gateway":"10.111.1.1",
                "routes":[ "10.222.1.0/24"]
              },
              "ipv6":{
                      "address":"2001:0db8:10:111:1::10/126",
                      "gateway":"2001:0db8:10:111:1::10",
                      "routes":["2001:0db8:10:222:1::0/126"]
              }
            }
          }
        }
      ]
spec:
  affinity:
